import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Обновление Fabric","description":"Пошаговая инструкция по обновлению Fabric.","frontmatter":{"title":"Обновление Fabric","description":"Пошаговая инструкция по обновлению Fabric.","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"ru_ru/1.21.1/players/updating-fabric.md","filePath":"versions/1.21.1/translated/ru_ru/players/updating-fabric.md","lastUpdated":1761424914000}`);var c={name:`ru_ru/1.21.1/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Обновление Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Обновление Fabric”">​</a></h1><p>В этом гайде мы расскажем вам об обновлении Fabric на официальном лаунчере Minecraft.</p><p>Для сторонних лаунчеров вам следует ознакомиться с их документацией.</p><p>Обновление Fabric - это процесс, очень похожий на установку Fabric, поэтому части этого гайда будут такими же, как и в гайде <a href="./installing-fabric">Установка Fabric</a>.</p><h2 id="why-should-i-update-fabric-loader" tabindex="-1">Почему я должен обновлять загрузчик Fabric? <a class="header-anchor" href="#why-should-i-update-fabric-loader" aria-label="Permalink to “Почему я должен обновлять загрузчик Fabric?”">​</a></h2><p>Для работы с новыми модами может потребоваться более новая версия загрузчика Fabric, поэтому важно поддерживать её в актуальном состоянии, чтобы вы могли использовать последние версии модов.</p><p>Для сторонних лаунчеров вам следует ознакомиться с их документацией.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Загрузка установщика Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Загрузка установщика Fabric”">​</a></h2><p>Вы можете загрузить установщик Fabric с <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">сайта Fabric</a>.</p><p>Если вы используете Windows, скачайте версию <code>.exe</code> (<code>Download For Windows</code>), потому что для неё не требуется Java в вашей системе. Вместо этого он использует версию Java из официального лаунчера.</p><p>Для macOS и Linux вам потребуется установить версию <code>.jar</code>. Иногда вам необходимо установить Java перед выполнением этого шага.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запуск установщика Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запуск установщика Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Перед установкой закройте Minecraft и лаунчер.</p></div><details class="details custom-block"><summary>Информация для пользователей macOS</summary><p>На macOS вам может потребоваться щелкнуть правой кнопкой мыши на файл <code>.jar</code> и нажать <code>Открыть</code>, чтобы запустить его.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Контекстное меню установщика Fabric на MacOS" loading="lazy"></p><p>Когда вас спросят: &quot;Вы уверены, что хотите это открыть?&quot;, нажмите <code>Открыть</code> ещё раз.</p></details><p>Как только вы откроете установщик, вы должны увидеть экран, похожий на этот:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Установщик Fabric с подсвеченным &quot;Install&quot;" loading="lazy"></p><p>Чтобы установить Fabric, просто выберите свою версию игры из списка и нажмите <code>Установить</code>.</p><p>Чтобы обновить Fabric, просто убедитесь в правильности версии игры и загрузчика, а затем нажмите <code>Установить</code>.</p><div class="warning custom-block"><p class="custom-block-title">ВАЖНО</p><p>Обязательно снимите флажок <code>Создать профиль</code> при установке, иначе появится новый профиль, который в данном случае нам не нужен.</p></div><h2 id="3-open-the-profile-in-the-minecraft-launcher" tabindex="-1">3. Откройте профиль в лаунчере Minecraft <a class="header-anchor" href="#3-open-the-profile-in-the-minecraft-launcher" aria-label="Permalink to “3. Откройте профиль в лаунчере Minecraft”">​</a></h2><p>Как только установка завершится, вы можете открыть лаунчер Minecraft и перейти во вкладку <code>Установки</code>. Вам следует зайти в профиль Fabric и открыть экран редактирования.</p><p>Замените версию загрузчика на новую, которую вы только что установили, и нажмите <code>Сохранить</code>.</p><p><img src="/assets/players/updating-fabric.png" alt="Обновление версии загрузчика Fabric в лаунчере Minecraft" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. Готово! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Готово!”">​</a></h2><p>Как только вы выполните все действия, вы можете вернуться в главную вкладку, выбрать профиль Fabric из списка в левом нижнем углу и нажать Играть!</p><p>Если вы столкнулись с какими-либо проблемами, попросите помощи в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">дискорде Fabric</a> в канале <code>#player-support</code>.</p>`,26)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};